import MainBtns from "../Components/Buttons/MainBtns";
import InputForm from "../Components/Input/InputForm";
import AdditionalInformation from "../Components/TextComponents/AdditionalInformation";
import TitleText from "../Components/TextComponents/TitleText";


function LoginPage() {
  return (
    <div>
      <TitleText TextOnTitle={"Выполните вход чтобы продолжить"}/>
      <InputForm TextPlaceholder="Адрес электронной почты"/>
      <InputForm TextPlaceholder={"Пароль"}/>
      <MainBtns Style={"purple-btn"} Text={"Продолжить"} Width={"400px"} Height={68} FontSize={"30px"} FontWeight={"100"} Padding={0} MarginTop={"auto"}  />
      <AdditionalInformation FirstText={"Не зарегистрированы?"} SecondText={"Регистрирация"} NavigateTo={"/register"}/>
    </div>
  );
}

export default LoginPage;
